import { createId } from '@paralleldrive/cuid2'
import { type AnyPgColumn, index, pgTable, text, timestamp, uniqueIndex } from './_shared'

import { User } from './user'

/** Drizzle table for verificationToken */
export const VerificationToken = pgTable(
  'VerificationToken',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    token: text().notNull(),
    userId: text()
      .notNull()
      .references((): AnyPgColumn => User.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    expiresAt: timestamp({ precision: 3 }).notNull(),
  },
  (table) => [
    uniqueIndex('VerificationToken_token_key').using('btree', table.token.asc().nullsLast()),
    index('VerificationToken_userId_idx').using('btree', table.userId.asc().nullsLast()),
  ]
)
